spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var centerY1 = H / 2 - 25;
    var centerY2 = H / 2 + 35;
    var padding = 40;
    var maxVal = 16;
    var spacing = (W - padding * 2) / maxVal;

    function getX(val) {
      return padding + val * spacing;
    }

    // Draw Number Lines
    function drawLine(y, label, valStep, color) {
      ctx.strokeStyle = '#4B5563';
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.moveTo(padding - 10, y);
      ctx.lineTo(W - padding + 10, y);
      ctx.stroke();

      // Labels and ticks
      for (var i = 0; i <= maxVal; i++) {
        var tx = getX(i);
        var isKey = (i > 0 && i % valStep === 0);

        ctx.strokeStyle = isKey ? color : '#374151';
        ctx.beginPath();
        ctx.moveTo(tx, y - 4);
        ctx.lineTo(tx, y + 4);
        ctx.stroke();

        ctx.fillStyle = isKey ? color : '#6B7280';
        ctx.font = '10px -apple-system, sans-serif';
        ctx.textAlign = 'center';
        ctx.fillText(i.toString(), tx, y + 15);
      }

      // Axis label
      ctx.fillStyle = '#9CA3AF';
      ctx.font = 'bold 11px -apple-system, sans-serif';
      ctx.textAlign = 'left';
      ctx.fillText(label, 15, y - 10);
    }

    drawLine(centerY1, 'Jumps of 4 (Multiples)', 4, '#60A5FA');
    drawLine(centerY2, 'Jumps of 6 (Multiples)', 6, '#EC4899');

    // Animation timing (8s cycle)
    var duration = 8000;
    var progress = (t % duration) / duration;

    var hopDuration = 0.15;
    // Line 1 hops (4 hops to reach 16)
    for (var h1 = 0; h1 < 4; h1++) {
      var startT1 = h1 * hopDuration;
      var endT1 = (h1 + 1) * hopDuration;
      if (progress > startT1) {
        var p = Math.min(1.0, (progress - startT1) / hopDuration);
        var x1 = getX(h1 * 4);
        var targetVal = h1 * 4 + 4 * p;
        var curX1 = getX(targetVal);

        ctx.strokeStyle = '#60A5FA';
        ctx.lineWidth = 3;
        ctx.beginPath();
        ctx.moveTo(x1, centerY1);
        var fullEndX = getX(h1 * 4 + 4);
        for (var x = x1; x <= curX1; x++) {
          var ratio = (x - x1) / (fullEndX - x1);
          ctx.lineTo(x, centerY1 - Math.sin(ratio * Math.PI) * 20);
        }
        ctx.stroke();
      }
    }

    // Line 2 hops (2.6 hops to reach 16, i.e., 3 hops to 18 (extends off graph slightly))
    for (var h2 = 0; h2 < 3; h2++) {
      var startT2 = h2 * hopDuration;
      var endT2 = (h2 + 1) * hopDuration;
      if (progress > startT2) {
        var p2 = Math.min(1.0, (progress - startT2) / hopDuration);
        var x2 = getX(h2 * 6);
        var targetVal2 = h2 * 6 + 6 * p2;
        var curX2 = getX(Math.min(maxVal, targetVal2));

        ctx.strokeStyle = '#EC4899';
        ctx.lineWidth = 3;
        ctx.beginPath();
        ctx.moveTo(x2, centerY2);
        var fullEndX2 = getX(h2 * 6 + 6);
        var drawLimit = Math.min(curX2, W - padding);
        for (var xx = x2; xx <= drawLimit; xx++) {
          var ratio2 = (xx - x2) / (fullEndX2 - x2);
          ctx.lineTo(xx, centerY2 - Math.sin(ratio2 * Math.PI) * 22);
        }
        ctx.stroke();
      }
    }

    // Vertical alignment line at 12
    if (progress > 0.50) {
      ctx.strokeStyle = '#10B981';
      ctx.lineWidth = 2.5;
      ctx.setLineDash([4, 4]);
      ctx.beginPath();
      ctx.moveTo(getX(12), centerY1);
      ctx.lineTo(getX(12), centerY2);
      ctx.stroke();
      ctx.setLineDash([]);

      // Draw alignment targets
      var pulse = Math.sin(t * 0.015) * 2;
      ctx.fillStyle = '#F59E0B';
      ctx.beginPath();
      ctx.arc(getX(12), centerY1, 6 + pulse, 0, Math.PI * 2);
      ctx.arc(getX(12), centerY2, 6 + pulse, 0, Math.PI * 2);
      ctx.fill();

      // Label
      ctx.fillStyle = '#34D399';
      ctx.font = 'bold 15px -apple-system, sans-serif';
      ctx.textAlign = 'center';
      ctx.fillText('LCM(4, 6) = 12', W / 2, centerY1 - 35);
    } else {
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '13px -apple-system, sans-serif';
      ctx.textAlign = 'center';
      ctx.fillText('Finding the first common multiple...', W / 2, centerY1 - 35);
    }
  }
};
